import { AsyncSliceState, CacheStrategy, CreateAsyncSlice, CreateSlice, MachineReducer, MachineSliceInfo, MachineSlices, RuntimeActionCreator, SliceContext, SliceKind, SliceReducer, StringTypes } from './models';
export declare namespace Slices {
    type SliceMapReducer = MachineReducer & {
        info: MachineSliceInfo;
    };
    type SliceMap = {
        reducer: SliceMapReducer;
        actionCreatorByType: {
            [K in StringTypes.ActionType]: RuntimeActionCreator;
        };
        actionCreatorListBySliceKey: {
            [K in StringTypes.SliceKey]: RuntimeActionCreator[];
        };
        actionCreatorsSliceKey: {
            [K in StringTypes.SliceKey]: {
                [K: string]: RuntimeActionCreator;
            };
        };
        actionTypesBySliceKey: {
            [K in StringTypes.SliceKey]: {
                [K: string]: string;
            };
        };
        reducerBySliceKey: {
            [K: StringTypes.SliceKey]: SliceMapReducer;
        };
        reducerByActionType: {
            [K in StringTypes.ActionType]: SliceMapReducer;
        };
        actionTypeList: StringTypes.ActionType[];
    };
    /** Explicit type for sync slice model */
    type SyncSliceModel = {
        id: string;
        kind: SliceKind.sync;
        initial: unknown;
        reducers: Record<string, SliceReducer>;
        cache: CacheStrategy;
    };
    /** Explicit type for async slice model */
    type AsyncSliceModel = {
        id: string;
        kind: SliceKind.async;
        initial: AsyncSliceState<unknown>;
        load: (...args: any[]) => Promise<unknown>;
        context: SliceContext;
        cache: CacheStrategy;
    };
    type SlicesMap = Omit<SliceMap, 'reducer'> & {
        info: MachineSliceInfo[];
        mergedSlicesInitialContext: SliceContext;
        mergedSlicesInitialState: AnyRecord;
    };
    const SyncSliceModel: import("..").Type<{
        properties: {
            id: "string";
