                readonly record: "function";
            };
            cache: import("..").Type<{
                properties: {
                    policy: {
                        readonly enum: ("public" | "private" | "session")[];
                    };
                    ttl: "string?";
                    swr: "boolean?";
                };
            }, {
                policy: unknown;
                ttl?: string | undefined;
                swr?: boolean | undefined;
            }>;
        };
    }, {
        id: string;
        kind: unknown;
        initial: unknown;
        reducers: unknown;
        cache: unknown;
    }>;
    const AsyncSliceModel: import("..").Type<{
        properties: {
            id: "string";
            kind: {
                readonly enum: readonly [SliceKind.async];
            };
            initial: "any";
            load: "function";
            context: "object";
            cache: import("..").Type<{
                properties: {
                    policy: {
                        readonly enum: ("public" | "private" | "session")[];
                    };
                    ttl: "string?";
                    swr: "boolean?";
                };
            }, {
                policy: unknown;
                ttl?: string | undefined;
                swr?: boolean | undefined;
            }>;
        };
    }, {
        id: string;
        kind: unknown;
        initial: any;
        load: import("..").FunctionLike;
        context: object;
        cache: unknown;
    }>;
    const AnySliceModel: import("..").Type<{
        readonly union: readonly [import("..").Type<{
            properties: {
                id: "string";
                kind: {
                    readonly enum: readonly [SliceKind.sync];
                };
                initial: "unknown";
                reducers: {
                    readonly record: "function";
                };
                cache: import("..").Type<{
                    properties: {
                        policy: {
                            readonly enum: ("public" | "private" | "session")[];
                        };
                        ttl: "string?";
                        swr: "boolean?";
                    };
                }, {
                    policy: unknown;
                    ttl?: string | undefined;
