    }, unknown>;
    function IsSyncSliceKind(value: unknown): value is SyncSliceModel;
    function IsAsyncSliceKind(value: unknown): value is AsyncSliceModel;
    const AsyncReducerNames: Set<"load" | "clear" | "success" | "fail">;
