import { NullableToPartial } from '../helpers/type-utils';
import { TSchema } from './lib/type';
/**
 * Core type definitions and public interfaces for the type validation system.
 */
export type AllTypes = {
    string: {};
    number: {};
    null: {};
    undefined: {};
    boolean: {};
    unknown: {};
    any: {};
    object: {
        properties: ObjectTypeProperties;
    };
    enum: {
        enum: ReadonlyArray<string>;
    };
    list: {
        items: TypeDefinition;
    };
    union: {
        union: ReadonlyArray<TypeDefinition>;
    };
    record: {
        record: TypeDefinition;
    };
    date: {};
    function: {};
    type: {
        '~typebox': TSchema;
    };
};
export type ObjectTypeProperties = {
    [K: string]: TypeDefinition;
};
export type TypeName = keyof AllTypes & {};
/**
 * Type definition using a compact string format.
 * Format: `typeName[?][[]][?]`
 */
export type TypeDefinitionString = `${TypeName}${'?' | ''}${'[]' | ''}${'?' | ''}`;
/**
 * Type definition using object-based format.
 */
export type ObjectBasedTypeDefinition = AllTypes['object'] | AllTypes['enum'] | AllTypes['list'] | AllTypes['union'] | AllTypes['record'] | AllTypes['type'];
/**
 * Union of all possible type definitions.
 */
export type TypeDefinition = TypeDefinitionString | ObjectBasedTypeDefinition;
export type FunctionLike = (...params: ReadonlyArray<any>) => any;
/**
 * Compiled type with validation methods.
 */
export type Type<_Definition extends TypeDefinition = TypeDefinition, Result = unknown> = {
    '~typebox': TSchema;
    list(): Type<any, Result[]>;
    parse<T>(value: T, property?: string): Result;
    parseList<T>(value: T, property?: string): Result[];
    isValid(value: unknown): value is Result;
};
type InferPrimitive<T extends string> = T extends 'string' ? string : T extends 'number' ? number : T extends 'boolean' ? boolean : T extends 'null' ? null : T extends 'undefined' ? undefined : T extends 'date' ? Date : T extends 'function' ? FunctionLike : T extends 'object' ? object : T extends 'unknown' ? unknown : T extends 'any' ? any : never;
type InferFromString<T extends string> = T extends `${infer Base}[]?` ? InferPrimitive<Base>[] | undefined : T extends `${infer Base}?[]` ? (InferPrimitive<Base> | undefined)[] : T extends `${infer Base}[]` ? InferPrimitive<Base>[] : T extends `${infer Base}?` ? InferPrimitive<Base> | undefined : InferPrimitive<T>;
type InferProperties<T extends ObjectTypeProperties> = NullableToPartial<{
    [K in keyof T]: T[K] extends string ? InferFromString<T[K]> : unknown;
}>;
/**
 * Infers TypeScript type from TypeDefinition.
 * Simplified to prevent infinite recursion.
 */
export type InferType<T> = T extends string ? InferFromString<T> : T extends {
    properties: infer P extends ObjectTypeProperties;
} ? InferProperties<P> : T extends {
    enum: infer E extends ReadonlyArray<string>;
} ? E[number] : T extends {
    items: infer I;
} ? I extends string ? InferFromString<I>[] : unknown[] : T extends {
    union: ReadonlyArray<infer U>;
} ? U extends string ? InferFromString<U> : unknown : T extends {
    record: infer R;
} ? Record<string, R extends string ? InferFromString<R> : unknown> : T extends {
    '~typebox': TSchema;
} ? unknown : unknown;
export {};

